#include <stdio.h>
#include <stdbool.h>

#define N 5  // Number of processes
#define M 3  // Number of resource types

bool isSafe(int avail[], int max[][M], int alloc[][M]) {
    int need[N][M];
    int work[M];
    bool finish[N] = {false};
    int safeSeq[N];

    // Calculate Need matrix
    for (int i = 0; i < N; i++)
        for (int j = 0; j < M; j++)
            need[i][j] = max[i][j] - alloc[i][j];

    // Copy available to work
    for (int j = 0; j < M; j++)
        work[j] = avail[j];

    int count = 0;
    while (count < N) {
        bool found = false;
        for (int i = 0; i < N; i++) {
            if (!finish[i]) {
                bool canFinish = true;
                for (int j = 0; j < M; j++) {
                    if (need[i][j] > work[j]) {
                        canFinish = false;
                        break;
                    }
                }
                if (canFinish) {
                    for (int j = 0; j < M; j++)
                        work[j] += alloc[i][j];
                    finish[i] = true;
                    safeSeq[count++] = i;
                    found = true;
                }
            }
        }
        if (!found) return false;
    }
    return true;
}

bool requestResources(int pid, int request[], int avail[], int max[][M], int alloc[][M]) {
    int need[N][M];
    for (int i = 0; i < N; i++)
        for (int j = 0; j < M; j++)
            need[i][j] = max[i][j] - alloc[i][j];

    // Check request <= need
    for (int j = 0; j < M; j++)
        if (request[j] > need[pid][j]) return false;

    // Check request <= available
    for (int j = 0; j < M; j++)
        if (request[j] > avail[j]) return false;

    // Pretend to allocate
    for (int j = 0; j < M; j++) {
        avail[j] -= request[j];
        alloc[pid][j] += request[j];
    }

    // Check safety
    if (isSafe(avail, max, alloc)) {
        return true;  // Grant request
    }

    // Rollback
    for (int j = 0; j < M; j++) {
        avail[j] += request[j];
        alloc[pid][j] -= request[j];
    }
    return false;  // Deny request
}

public class BankersAlgorithm {
    private int processes;
    private int resources;
    private int[] available;
    private int[][] maximum;
    private int[][] allocation;
    private int[][] need;

    public BankersAlgorithm(int[] available, int[][] maximum, int[][] allocation) {
        this.available = available;
        this.maximum = maximum;
        this.allocation = allocation;
        this.processes = maximum.length;
        this.resources = available.length;
        calculateNeed();
    }

    private void calculateNeed() {
        need = new int[processes][resources];
        for (int i = 0; i < processes; i++) {
            for (int j = 0; j < resources; j++) {
                need[i][j] = maximum[i][j] - allocation[i][j];
            }
        }
    }

    public boolean isSafe() {
        int[] work = available.clone();
        boolean[] finish = new boolean[processes];
        int[] safeSequence = new int[processes];
        int count = 0;

        while (count < processes) {
            boolean found = false;
            for (int i = 0; i < processes; i++) {
                if (!finish[i] && canFinish(i, work)) {
                    for (int j = 0; j < resources; j++) {
                        work[j] += allocation[i][j];
                    }
                    finish[i] = true;
                    safeSequence[count++] = i;
                    found = true;
                }
            }
            if (!found) return false;
        }
        return true;
    }

    private boolean canFinish(int processId, int[] work) {
        for (int j = 0; j < resources; j++) {
            if (need[processId][j] > work[j]) return false;
        }
        return true;
    }

    public boolean requestResources(int processId, int[] request) {
        // Check request <= need
        for (int j = 0; j < resources; j++) {
            if (request[j] > need[processId][j]) return false;
        }
        // Check request <= available
        for (int j = 0; j < resources; j++) {
            if (request[j] > available[j]) return false;
        }
        // Pretend to allocate
        for (int j = 0; j < resources; j++) {
            available[j] -= request[j];
            allocation[processId][j] += request[j];
            need[processId][j] -= request[j];
        }

        if (isSafe()) return true;

        // Rollback
        for (int j = 0; j < resources; j++) {
            available[j] += request[j];
            allocation[processId][j] -= request[j];
            need[processId][j] += request[j];
        }
        return false;
    }
}
